    }

    if (GoogleAuthSession.instance.isSessionBlocked) {
      await _logApiError(
        tag: 'CalendarExcelMailer.sendBreakMonthExcel',
        message: '구글 세션 차단(ON) 상태로 이메일 전송 차단됨',
        error: StateError('google_session_blocked'),
        extra: <String, dynamic>{'year': year, 'month': month},
        tags: const <String>[_tCal, _tMailer, _tEmail],
      );
      throw StateError('구글 세션 차단(ON) 상태입니다. 전송을 위해 OFF로 변경해 주세요.');
    }

    List<int> bytes;
    try {
      bytes = _buildBreakExcelBytes(
        year: year,
        month: month,
        userId: userId,
        userName: userName,
        breakByDay: breakByDay,
      );
    } catch (e) {
      await _logApiError(
        tag: 'CalendarExcelMailer.sendBreakMonthExcel',
        message: '휴게 엑셀 생성 실패',
        error: e,
        extra: <String, dynamic>{
          'year': year,
          'month': month,
          'userIdLen': userId.length,
          'userNameLen': userName.length,
          'breakDays': breakByDay.length,
        },
        tags: const <String>[_tCal, _tMailer, _tExcel],
      );
      rethrow;
    }

    final ym = '${year}${month.toString().padLeft(2, '0')}';
    final safeUserId = _sanitizeFilePart(userId);
    final filename = 'break_${safeUserId}_${ym}.xlsx';

    final finalSubject = subject ?? '[휴게시간] $userName ($userId) $ym';
    final finalBody = body ??
        '첨부된 엑셀 파일에 $year-${month.toString().padLeft(2, '0')} 휴게 데이터가 포함되어 있습니다.\n'
            '- 제공된 휴게시간 공통 템플릿 구조를 사용합니다.\n'
            '- A안에 따라 시작 행만 채우고 종료 행은 비워 둡니다.\n';

    await _sendGmailWithAttachment(
      toCsv: to,
      subject: finalSubject,
      body: finalBody,
      filename: filename,
      mimeType: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
      attachmentBytes: bytes,
      debugExtra: <String, dynamic>{
        'kind': 'break',
        'year': year,
        'month': month,
        'userIdLen': userId.length,
        'userNameLen': userName.length,
        'bytes': bytes.length,
      },
    );
  }

  static List<int> _buildAttendanceExcelBytes({
    required int year,
    required int month,
    required String userId,
    required String userName,
    required Map<int, String> clockInByDay,
    required Map<int, String> clockOutByDay,
  }) {
    final excel = _decodeTemplate(_attendanceTemplateB64);
    final sheet = _pickSheet(excel);

    final area = _inferAreaFromUserId(userId);
    _setText(sheet, 0, 1, '  현장명 : ${area.isEmpty ? userId : area}');
    _setText(sheet, 0, 3, '1');
    _setText(sheet, 1, 3, '');
    _setText(sheet, 2, 3, userName);

    final lastDay = DateTime(year, month + 1, 0).day;

    for (var day = 1; day <= 31; day++) {
      final inPos = _attendancePosition(day, false);
      final outPos = _attendancePosition(day, true);
      final inValue = day <= lastDay ? (clockInByDay[day] ?? '').trim() : '';
      final outValue = day <= lastDay ? (clockOutByDay[day] ?? '').trim() : '';
      _setText(sheet, inPos.col, inPos.row, inValue);
      _setText(sheet, outPos.col, outPos.row, outValue);
    }

    final bytes = excel.encode();
    if (bytes == null) throw StateError('엑셀 인코딩 실패');
    return bytes;
  }

  static List<int> _buildBreakExcelBytes({
    required int year,
    required int month,
    required String userId,
    required String userName,
    required Map<int, String> breakByDay,
  }) {
    final excel = _decodeTemplate(_breakTemplateB64);
    final sheet = _pickSheet(excel);

    final area = _inferAreaFromUserId(userId);
    _setText(sheet, 0, 1, '  현장명 : ${area.isEmpty ? userId : area}');
    _setText(sheet, 0, 3, '1');
    _setText(sheet, 1, 3, '');
    _setText(sheet, 2, 3, userName);

    final lastDay = DateTime(year, month + 1, 0).day;

    for (var day = 1; day <= 31; day++) {
      final startPos = _breakStartPosition(day);
      final endPos = _breakEndPosition(day);
      final value = day <= lastDay ? (breakByDay[day] ?? '').trim() : '';
      _setText(sheet, startPos.col, startPos.row, value);
      _setText(sheet, endPos.col, endPos.row, '');
    }

    final bytes = excel.encode();
    if (bytes == null) throw StateError('엑셀 인코딩 실패');
    return bytes;
  }

  static Excel _decodeTemplate(String b64) {
    return Excel.decodeBytes(Uint8List.fromList(base64Decode(b64)));
  }

  static Sheet _pickSheet(Excel excel) {
    if (excel.tables.containsKey('캔버스랩')) {
      return excel['캔버스랩'];
    }
    if (excel.tables.isNotEmpty) {
      return excel[excel.tables.keys.first];
    }
    throw StateError('시트를 찾을 수 없습니다.');
  }

  static _GridPos _attendancePosition(int day, bool isOut) {
    if (day < 1 || day > 31) {
      throw RangeError.range(day, 1, 31, 'day');
    }
    if (day <= 17) {
      return _GridPos(
        4 + (day - 1),
        isOut ? 5 : 4,
      );
    }
    return _GridPos(
      4 + (day - 18),
      isOut ? 8 : 7,
    );
  }

  static _GridPos _breakStartPosition(int day) {
    if (day < 1 || day > 31) {
      throw RangeError.range(day, 1, 31, 'day');
    }
    if (day <= 17) {
      return _GridPos(4 + (day - 1), 4);
    }
    return _GridPos(4 + (day - 18), 7);
  }

  static _GridPos _breakEndPosition(int day) {
    if (day < 1 || day > 31) {
      throw RangeError.range(day, 1, 31, 'day');
    }
    if (day <= 17) {
      return _GridPos(4 + (day - 1), 5);
    }
    return _GridPos(4 + (day - 18), 8);
  }

  static void _setText(Sheet sheet, int col, int row, String value) {
    sheet
        .cell(CellIndex.indexByColumnRow(columnIndex: col, rowIndex: row))
        .value = TextCellValue(value);
  }

  static String _inferAreaFromUserId(String userId) {
    final idx = userId.indexOf('-');
    if (idx == -1 || idx + 1 >= userId.length) {
      return '';
    }
    return userId.substring(idx + 1).trim();
  }

  static Future<void> _sendGmailWithAttachment({
    required String toCsv,
    required String subject,
    required String body,
    required String filename,
    required String mimeType,
    required List<int> attachmentBytes,
    Map<String, dynamic>? debugExtra,
  }) async {
    try {
      final client = await GoogleAuthSession.instance.safeClient();
      final api = gmail.GmailApi(client);

      final boundary = '----ParkinWorkin_${DateTime.now().millisecondsSinceEpoch}';
      final attachmentB64 = _wrapBase64(base64.encode(attachmentBytes));

      const crlf = '\r\n';
      final mime = StringBuffer()
        ..write('MIME-Version: 1.0$crlf')
        ..write('To: $toCsv$crlf')
        ..write('Subject: ${_encodeHeaderIfNeeded(subject)}$crlf')
        ..write('Content-Type: multipart/mixed; boundary="$boundary"$crlf')
        ..write(crlf)
        ..write('--$boundary$crlf')
        ..write('Content-Type: text/plain; charset="UTF-8"$crlf')
        ..write('Content-Transfer-Encoding: 7bit$crlf')
        ..write(crlf)
        ..write(body)
        ..write(crlf)
        ..write('--$boundary$crlf')
        ..write('Content-Type: $mimeType; name="$filename"$crlf')
        ..write('Content-Disposition: attachment; filename="$filename"$crlf')
        ..write('Content-Transfer-Encoding: base64$crlf')
        ..write(crlf)
        ..write(attachmentB64)
        ..write('--$boundary--$crlf');

      final raw = _base64UrlNoPad(utf8.encode(mime.toString()));
      final msg = gmail.Message()..raw = raw;
      await api.users.messages.send(msg, 'me');
    } catch (e) {
      await _logApiError(
        tag: 'CalendarExcelMailer._sendGmailWithAttachment',
        message: 'Gmail 첨부 메일 전송 실패',
        error: e,
        extra: <String, dynamic>{
          'toLen': toCsv.trim().length,
          'subjectLen': subject.trim().length,
          'filename': filename,
          'mimeType': mimeType,
          'bytes': attachmentBytes.length,
          if (debugExtra != null) ...debugExtra,
        },
        tags: const <String>[_tCal, _tMailer, _tEmail, _tGmail],
      );
      rethrow;
    }
  }

  static String _base64UrlNoPad(List<int> bytes) {
    return base64Url.encode(bytes).replaceAll('=', '');
  }

  static String _wrapBase64(String input, {int lineLength = 76}) {
    final sb = StringBuffer();
    for (var i = 0; i < input.length; i += lineLength) {
      final end = (i + lineLength < input.length) ? i + lineLength : input.length;
      sb.write(input.substring(i, end));
      sb.write('\r\n');
    }
    return sb.toString();
  }

  static String _encodeHeaderIfNeeded(String s) {
    final hasNonAscii = s.codeUnits.any((c) => c > 127);
    if (!hasNonAscii) return s;
    final b64 = base64.encode(utf8.encode(s));
    return '=?UTF-8?B?$b64?=';
  }

  static String _sanitizeFilePart(String s) {
    return s.replaceAll(RegExp(r'[^a-zA-Z0-9._-]+'), '_');
  }
}

class _GridPos {
  final int col;
  final int row;

  const _GridPos(this.col, this.row);
}
